Title

I have autofocus disabled but it still autofocuses by default and jumps the browser down to the search

```js
var users;
$(document).ready(function() {
  if($('#search-box').length) {

    const search = instantsearch({
      appId: 'appId',
      apiKey: 'key',
      indexName: 'index',
      urlSync: true,
      autofocus: false,
      searchFunction: function(helper) {
        var searchResults = $('#hits');
        if (helper.state.query === '') {
          // empty query string -> hide the search results & abort the search
          searchResults.hide();
          return;
        }
        // perform the regular search & display the search results
        helper.search();
        searchResults.show();
      }
    });

    // initialize SearchBox
    search.addWidget(
      instantsearch.widgets.searchBox({
        container: '#search-box',
        placeholder: 'Search for Agents, Actors, Movies, etc.',
        poweredBy: true
      })
    );

    // initialize clearAll
    search.addWidget(
      instantsearch.widgets.clearAll({
        container: '#clear-all',
        templates: {
          link: 'Reset everything'
        },
        autoHideContainer: false
      })
    );

    // initialize pagination
    search.addWidget(
      instantsearch.widgets.pagination({
        container: '#pagination',
        maxPages: 20,
        // default is to scroll to 'body', here we disable this behavior
        scrollTo: false
      })
    );

    search.addWidget(
      instantsearch.widgets.hits({
        container: '#hits',
        templates: {
          empty: 'No results',
          item: '<a href="https://theareel.com/{{username}}">{{name}}</a>'
        }
      })
    );

    search.templatesConfig.helpers.highlightResults = function (text, render){
      var data = render(text);
      return modifiedData(data)
    }

    search.addWidget(
      instantsearch.widgets.refinementList({
        container: '#eyecolorRefine',
        attributeName: 'eyecolor',
        operator: 'or',
        limit: 10,
        templates: {
          header: 'Eye Color'
        }
      })
    );

    search.addWidget(
      instantsearch.widgets.refinementList({
        container: '#haircolorRefine',
        attributeName: 'haircolor',
        operator: 'or',
        limit: 10,
        templates: {
          header: 'Hair Color'
        }
      })
    );

    search.addWidget(
      instantsearch.widgets.refinementList({
        container: '#ethnicityRefine',
        attributeName: 'ethnicity',
        operator: 'or',
        limit: 10,
        templates: {
          header: 'Ethnicity'
        }
      })
    );

    search.addWidget(
      instantsearch.widgets.rangeSlider({
        container: '#ageSlider',
        attributeName: 'dob',
        templates: {
          header: 'Age'
        },
        tooltips: {
          format: function(rawValue) {
            return Math.round(rawValue).toLocaleString();
          }
        }
      })
    );

    search.addWidget(
      instantsearch.widgets.rangeSlider({
        container: '#heightSlider',
        attributeName: 'height',
        templates: {
          header: 'Height'
        },
        tooltips: {
          format: function(rawValue) {
            return Math.round(rawValue).toLocaleString();
          }
        }
      })
    );

    search.start();
  }
});
```
